const items = $input.all();

const check_date = new Date().toLocaleDateString('en-IN', {
  day: '2-digit',
  month: 'long',
  year: 'numeric'
});

// Convert to clean JSON
const data = items.map(i => i.json);

// Group by state
const stateMap = {};

// Step 1: group rows by state
for (const row of data) {
  const state = row.state;

  if (!stateMap[state]) {
    stateMap[state] = [];
  }

  stateMap[state].push(row);
}

// Step 2: sort each state by date
for (const state in stateMap) {
  stateMap[state].sort((a, b) => new Date(a.date) - new Date(b.date));
}

const stateData = [];

for (const state in stateMap) {
  const records = stateMap[state];

  if (records.length < 3) continue;

  const last3 = records.slice(-3);

  const day1 = Number(last3[0].daily_new_cases || 0);
  const day2 = Number(last3[1].daily_new_cases || 0);
  const day3 = Number(last3[2].daily_new_cases || 0);

  const latest = last3[2];

  stateData.push({
    state: state,
    cases_day1: day1,
    cases_day2: day2,
    cases_day3: day3,
    positivity_rate: Number(latest.positive_rate || 0),
    vax_growth_rate: Number(latest.vaccination_growth || 0),
    total_confirmed: Number(latest.confirmed || 0),
    total_deaths: Number(latest.deaths || 0)
  });
}

const POSITIVITY_THRESHOLD = 5.0;
const VAX_GROWTH_THRESHOLD = 2.0;
const thresholds = {
  positivity: POSITIVITY_THRESHOLD,
  vax_growth: VAX_GROWTH_THRESHOLD,
  rising_days: 3
};
const alerts = [];

for (const s of stateData) {
  const risingCases = (
    s.cases_day3 > s.cases_day2 &&
    s.cases_day2 > s.cases_day1
  );

  const highPositivity = s.positivity_rate > POSITIVITY_THRESHOLD;
  const lowVaxGrowth = s.vax_growth_rate < VAX_GROWTH_THRESHOLD;

  const conditionsMet = [risingCases, highPositivity, lowVaxGrowth]
    .filter(Boolean).length;

  if (conditionsMet >= 2) {

    let riskLevel = 'LOW';
    if (conditionsMet === 3) riskLevel = 'HIGH';
    else if (conditionsMet === 2) riskLevel = 'MEDIUM';

    const caseGrowth = (
      ((s.cases_day3 - s.cases_day1) / s.cases_day1) * 100
    ).toFixed(1);

    alerts.push({
      state: s.state,
      risk_level: riskLevel,
      case_growth_pct: parseFloat(caseGrowth),
      positivity_rate: s.positivity_rate,
      vax_growth_rate: s.vax_growth_rate
    });
  }
}

return [{
  json: {
    check_date,
    total_alerts: alerts.length,
    high_risk_states: alerts.filter(a => a.risk_level === 'HIGH').map(a => a.state),
    medium_risk_states: alerts.filter(a => a.risk_level === 'MEDIUM').map(a => a.state),
    all_alert_states: alerts,
    thresholds
  }
}];

